<?php
namespace App\Filament\Resources; use App\Filament\Resources\AreaCommentResource\Pages; use App\Modules\Area\Models\AreaComment; use Filament\Forms; use Filament\Forms\Form; use Filament\Resources\Resource; use Filament\Tables; use Filament\Tables\Table;
class AreaCommentResource extends Resource { protected static ?string $model=AreaComment::class; protected static ?string $navigationIcon='heroicon-o-chat-bubble-bottom-center-text'; protected static ?string $navigationGroup='Bình luận'; protected static ?string $modelLabel='Bình luận khu đất'; protected static ?string $pluralModelLabel='Bình luận khu đất'; public static function form(Form $form): Form { return $form->schema([Forms\Components\Select::make('area_id')->label('Khu đất')->relationship('area','name')->searchable()->preload()->required(), Forms\Components\Select::make('user_id')->label('Người viết')->relationship('user','name')->searchable()->preload()->required(), Forms\Components\Textarea::make('content')->label('Nội dung')->required()->columnSpanFull()])->columns(2); } public static function table(Table $table): Table { return $table->columns([Tables\Columns\TextColumn::make('area.name')->label('Khu đất'), Tables\Columns\TextColumn::make('user.name')->label('Người viết'), Tables\Columns\TextColumn::make('content')->label('Nội dung')->limit(70), Tables\Columns\TextColumn::make('created_at')->label('Ngày')->dateTime('d/m/Y H:i')])->actions([Tables\Actions\EditAction::make(),Tables\Actions\DeleteAction::make()]); } public static function getPages(): array { return ['index'=>Pages\ListAreaComments::route('/'),'create'=>Pages\CreateAreaComment::route('/create'),'edit'=>Pages\EditAreaComment::route('/{record}/edit')]; } }
